        colors: cyanPalette,
        plotOptions: distributed,
        data: [
          { x: 'Compute', y: 110 },
          { x: 'Storage', y: 80 },
          { x: 'Networking', y: 45 },
          { x: 'Analytics', y: 25 },
        ],
      },
      {
