        data: [
          { x: 'Renewables', y: 160 },
          { x: 'Oil & Gas', y: 90 },
          { x: 'Utilities', y: 40 },
        ],
      },
      {
        id: 'consumer',
        name: 'Consumer',
        colors: purplePalette,
        plotOptions: distributed,
        data: [
          { x: 'Retail', y: 180 },
          { x: 'Food & Beverage', y: 100 },
          { x: 'Apparel', y: 60 },
        ],
      },
    ],
  },
}

var chart = new ApexCharts(document.querySelector('#chart'), options)
chart.render()
